// Prepare context for AI analysis
const items = $input.all();
const topContent = items.filter(i => i.json.last_week_sessions !== undefined).map(i => i.json);
const decayingContent = items.filter(i => i.json.decline_percent !== undefined).map(i => i.json);

const context = {
  top_performing: topContent.slice(0, 10).map(c => ({
    url: c.url,
    title: c.title,
    sessions: c.last_week_sessions,
    bounce_rate: c.bounce_rate,
    word_count: c.word_count
  })),
  decaying: decayingContent.slice(0, 5).map(c => ({
    page: c.page,
    decline: c.decline_percent,
    current: c.current_sessions,
    historical: c.historical_sessions
  })),
  analysis_date: new Date().toISOString().split('T')[0]
};

return [{ json: context }];

