// Parse AI response and store insights
const response = $input.first().json;
const content = response.content?.[0]?.text || '{"insights": []}';

let parsed;
try {
  // Extract JSON from response
  const jsonMatch = content.match(/\{[\s\S]*\}/);
  parsed = JSON.parse(jsonMatch ? jsonMatch[0] : content);
} catch (e) {
  parsed = { insights: [] };
}

const insights = (parsed.insights || []).map(i => ({
  insight_type: 'content_recommendation',
  category: 'content',
  title: i.title,
  summary: i.summary,
  priority: i.priority || 'medium',
  recommended_actions: JSON.stringify([{ action: i.action, effort: 'medium', impact: 'medium' }]),
  data_sources: ['content_inventory', 'page_traffic', 'content_decay_candidates'],
  confidence_score: 0.8,
  model_used: 'claude-3-haiku'
}));

return insights.length > 0 ? insights.map(i => ({ json: i })) : [{ json: { skip: true } }];
